// ─── URL helpers ─────────────────────────────────────────────────

const THIS_URL = import.meta.url;
const UI_DIR   = THIS_URL.replace(/\/[^/]+$/, '/');
const ROOT_DIR = UI_DIR.replace(/ui\/$/, '');

function rootUrl(path) { return ROOT_DIR + path; }
function uiUrl(name)   { return UI_DIR  + name; }

console.log('[archive] Base URL:', ROOT_DIR);

// ─── Fetch with fallback ─────────────────────────────────────────

async function fetchFile(url) {
  try {
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 8000);
    const resp = await fetch(url, {
      signal: ctrl.signal,
      cache: 'no-store',
      credentials: 'omit',
    });
    clearTimeout(timer);
    if (resp.ok) {
      const text = await resp.text();
      if (text && text.length > 0) {
        console.log(`[archive] OK: ${url.split('/').pop()} (${text.length}b)`);
        return text;
      }
      console.warn(`[archive] empty: ${url}`);
    } else {
      console.warn(`[archive] HTTP ${resp.status}: ${url}`);
    }
  } catch (e) {
    console.warn(`[archive] fail: ${url.split('/').pop()} — ${e.name}: ${e.message}`);
  }
  return null;
}

