async function bootApp(){window.__appBooted=true;await loadOptionalModules();addLogoutButton();addSyncIndicator();const appRoot=document.getElementById('appRoot');if(appRoot)appRoot.style.opacity='0.4';try{await main();handleHashNavigation();}catch(err){console.error('Boot error:',err);const banner=document.createElement('div');banner.style.cssText='position:fixed;top:0;left:0;right:0;z-index:9998;background:rgba(239,68,68,0.15);border-bottom:1px solid rgba(239,68,68,0.3);padding:0.5rem 1rem;font-size:0.75rem;color:rgb(252,165,165);text-align:center;';banner.textContent='⚠ Ошибка загрузки: '+(err&&err.message?err.message:String(err));document.body.appendChild(banner);}finally{if(appRoot)appRoot.style.opacity='1';}}
