async function fetchLibWithFallback(libDef) {
  for (const url of libDef.urls) {
    for (let attempt = 1; attempt <= 2; attempt++) {
      const ctrl = new AbortController();
      const timer = setTimeout(() => ctrl.abort(), 20000);
      try {
        const fetchUrl = url + (url.includes('?') ? '&' : '?') + '_t=' + Date.now() + '-' + attempt;
        const resp = await fetch(fetchUrl, {
          signal: ctrl.signal,
          cache: 'no-store',
          credentials: 'omit',
        });
        clearTimeout(timer);
        if (resp.ok) {
          const text = await resp.text();
          if (text && text.length > 10000) {
            console.log(`[archive] lib OK from ${url.split('/')[2]}: ${libDef.path} (${(text.length/1024).toFixed(0)}KB)`);
            return text;
          }
          console.warn(`[archive] lib short response ${url.split('/')[2]}: ${libDef.path}`);
        } else {
          console.warn(`[archive] lib HTTP ${resp.status} ${url.split('/')[2]}: ${libDef.path}`);
        }
      } catch (e) {
        clearTimeout(timer);
        console.warn(`[archive] lib fail ${url.split('/')[2]} attempt ${attempt}: ${e.message}`);
      }
    }
  }
  console.warn(`[archive] optional lib mirrors failed for ${libDef.path}`);
  return null;
}

