export async function downloadArchive(btn) {
  const originalHTML = btn ? btn.innerHTML : '';
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = '<span style="display:inline-flex;align-items:center;gap:6px">'
      + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" '
      + 'style="animation:spin 1s linear infinite"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg>'
      + '<span>Загрузка…</span></span>';
  }

  if (!document.getElementById('_archiveSpinStyle')) {
    const s = document.createElement('style');
    s.id = '_archiveSpinStyle';
    s.textContent = '@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}';
    document.head.appendChild(s);
  }

  let JSZipClass;
  try {
    JSZipClass = await loadJSZip();
  } catch (e) {
    showToast('Не удалось загрузить JSZip: ' + e.message, 'error');
    if (btn) { btn.disabled = false; btn.innerHTML = originalHTML; }
    return;
  }

  if (btn) {
    btn.innerHTML = '<span style="display:inline-flex;align-items:center;gap:6px">'
      + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" '
      + 'style="animation:spin 1s linear infinite"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg>'
      + '<span>Упаковка…</span></span>';
  }

  try {
    const zip = new JSZipClass();
    let okCount = 0;
    let failCount = 0;
    const failedPaths = [];

    // 1. index.html — сначала пробуем актуальный файл, embedded-версия остаётся fallback.
    // Это важно для новых модулей: embedded-копия может быть старше текущего index.html.
    let indexHtml = INDEX_HTML;
    const liveIndexHtml = await fetchFile(rootUrl('index.html'));
    if (liveIndexHtml && liveIndexHtml.includes('thAnalysisModal') && liveIndexHtml.includes('thFileInput')) {
      indexHtml = liveIndexHtml;
      console.log('[archive] using live index.html');
    }
    // Защита резервной embedded-копии: Разбор ТХ всегда принимает DOCX.
    indexHtml = indexHtml
      .replace(/Загрузите PDF с таблицей\./g, 'Загрузите Word .docx с таблицей.')
      .replace(/Выберите PDF-файл/g, 'Выберите Word-файл (.docx)')
      .replace(/или перетащите PDF сюда/g, 'или перетащите Word-файл сюда')
      .replace(/accept=["']application\/pdf,\.pdf["']/g, 'accept="application/vnd.openxmlformats-officedocument.wordprocessingml.document,.docx"')
      .replace(/aria-label=["']Выберите PDF с таблицей оснащения["']/g, 'aria-label="Выберите Word-файл с таблицей оснащения"');
    if (!indexHtml.includes('reportsAiMenuBtn')) {
      // Добавляем кнопку ИИ-ассистента и панель reportsAiPanel в reportsModal
      indexHtml = indexHtml.replace(
        /(<\/button><\/div><\/div>)(<div id="reportsDonmPanel")/,
        '$1<div id="reportsAiPanel" style="display:none;flex-direction:column;flex:1 1 0;min-height:0;overflow:hidden;"><div style="display:flex;align-items:center;justify-content:space-between;padding:0.75rem 1.5rem;border-bottom:1px solid rgba(255,255,255,0.07);flex-shrink:0;"><div style="display:flex;align-items:center;gap:0.75rem;"><button id="reportsAiBackBtn" type="button" style="background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:0.75rem;padding:0.4rem 0.75rem;font-size:0.8rem;color:#94a3b8;cursor:pointer;">← К отчётам</button><span style="font-size:0.9rem;font-weight:600;color:#fff;">🤖 ИИ-ассистент</span><span id="aiReportsModeIndicator" style="display:none;font-size:0.68rem;color:rgb(100,116,139);margin-left:0.5rem;"></span></div><div style="display:flex;gap:0.5rem;"><button id="aiReportsClearBtn" type="button" style="background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:0.75rem;padding:0.4rem 0.75rem;font-size:0.8rem;color:#94a3b8;cursor:pointer;">🗑️ Очистить</button><button id="aiReportsExportBtn" type="button" class="hidden" style="background:rgba(34,197,94,0.9);border:none;border-radius:0.75rem;padding:0.4rem 1rem;font-size:0.8rem;font-weight:700;color:#fff;cursor:pointer;">📥 Excel</button></div></div><div style="flex:0 0 auto;max-height:45%;overflow-y:auto;padding:1rem 1.5rem 0.5rem;" id="aiReportsFeed"></div><div style="flex-shrink:0;padding:0.75rem 1.5rem;border-top:1px solid rgba(255,255,255,0.07);display:flex;gap:0.5rem;align-items:flex-end;background:rgba(2,6,23,0.8);"><textarea id="aiReportsInput" rows="2" style="flex:1;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:0.75rem;padding:0.6rem 0.9rem;font-size:0.82rem;color:#e2e8f0;resize:none;outline:none;font-family:inherit;" placeholder="Задайте вопрос о данных проекта…"></textarea><button id="aiReportsSendBtn" type="button" style="flex-shrink:0;background:linear-gradient(135deg,rgb(6,182,212),rgb(34,211,238));border:none;border-radius:0.75rem;padding:0.6rem 1rem;color:#000;font-size:0.82rem;font-weight:700;cursor:pointer;min-width:80px;">Спросить</button></div><div id="aiReportsTableWrap" style="flex:1 1 0;min-height:0;overflow-y:auto;overflow-x:auto;padding:0 1.5rem 3rem;"></div></div>$2'
      );
      // Добавляем кнопку в меню отчётов (перед reportsDonmMenuBtn)
      indexHtml = indexHtml.replace(
        /id="reportsDonmMenuBtn"/,
        'id="reportsAiMenuBtn" type="button" onclick="" style="display:none;"></button><button id="reportsDonmMenuBtn"'
      );
      // Более простой способ: добавляем обработчик через script в конце body
      indexHtml = indexHtml.replace(
        '</body>',
        `<script>
document.addEventListener('DOMContentLoaded',function(){
  var aiMenuBtn=document.getElementById('reportsAiMenuBtn');
  var aiPanel=document.getElementById('reportsAiPanel');
  var menuPanel=document.getElementById('reportsMenuPanel');
  var donmPanel=document.getElementById('reportsDonmPanel');
  if(aiMenuBtn&&aiPanel&&menuPanel){
    aiMenuBtn.style.display='flex';
    aiMenuBtn.addEventListener('click',function(){
      menuPanel.classList.add('hidden');
      if(donmPanel)donmPanel.classList.add('hidden');
      aiPanel.style.display='flex';
    });
  }
  var aiBackBtn=document.getElementById('reportsAiBackBtn');
  if(aiBackBtn&&aiPanel&&menuPanel){
    aiBackBtn.addEventListener('click',function(){
      aiPanel.style.display='none';
      menuPanel.classList.remove('hidden');
    });
  }
});
<\/script></body>`
      );
    }
    zip.file('index.html', indexHtml);
    okCount++;
    console.log('[archive] embedded: index.html');

    // 1b. main.js — берём актуальный файл, embedded-версия остаётся fallback.
    const liveMainJs = await fetchFile(rootUrl('main.js'));
    const archiveMainJs = liveMainJs && liveMainJs.includes('th-analysis-view') ? liveMainJs : MAIN_JS;
    zip.file('main.js', archiveMainJs);
    okCount++;
    console.log('[archive] embedded: main.js');

    // 1c. doc-checker/index.html — вшит как строка (платформа трансформирует HTML при fetch)
    zip.file('doc-checker/index.html', DOC_CHECKER_INDEX_HTML);
    okCount++;
    console.log('[archive] embedded: doc-checker/index.html');

    // 2. Вшитые статические файлы
    for (const [filePath, content] of Object.entries(STATIC_FILES)) {
      zip.file(filePath, content);
      okCount++;
      console.log('[archive] embedded:', filePath);
    }

    // 3. API embedded files
    for (const [filePath, content] of Object.entries(API_FILES)) {
      zip.file(filePath, content);
      okCount++;
      console.log('[archive] api embedded:', filePath);
    }

    // 4. Fetch локальные библиотеки с CDN fallback
    const libResults = await Promise.all(LIB_URLS.map(libDef => fetchLibWithFallback(libDef)));
    for (let i = 0; i < LIB_URLS.length; i++) {
      if (libResults[i]) {
        zip.file(LIB_URLS[i].path, libResults[i]);
        okCount++;
      } else {
        failCount++;
        failedPaths.push(LIB_URLS[i].path);
      }
    }

    // 5. Fetch все остальные файлы основного приложения (JS/CSS/JSON)
    const fileList = getFileList();
    console.log(`[archive] Fetching ${fileList.length} files from ${ROOT_DIR}`);
    const results = await Promise.all(
      fileList.map(({ path, url }) => fetchFile(url).then(content => ({ path, content })))
    );
    for (const { path, content } of results) {
      if (content !== null) { zip.file(path, content); okCount++; }
      else { failCount++; failedPaths.push(path); }
    }

    console.log(`[archive] Results: ${okCount} OK, ${failCount} failed`);
    if (failCount > 0) {
      console.warn('[archive] Failed files:', failedPaths);
    }

    // Generate and download ZIP
    const blob = await zip.generateAsync({
      type: 'blob',
      compression: 'DEFLATE',
      compressionOptions: { level: 6 },
    });
    const dlUrl = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = dlUrl;
    a.download = 'osnashchenie-app.zip';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(dlUrl), 15000);

    const sizeKB = (blob.size / 1024).toFixed(0);
    const msg = failCount > 0
      ? `Скачано: ${okCount} файлов, ${sizeKB} КБ (${failCount} не загружено — полный архив на сервере)`
      : `Архив готов: ${okCount} файлов, ${sizeKB} КБ`;
    showToast(msg, failCount > 0 ? 'warning' : 'success');

  } catch (err) {
    console.error('[archive] Error:', err);
    showToast('Ошибка архива: ' + err.message, 'error');
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = originalHTML;
    }
  }
}
